const WebSocket = require('ws');
const wss = new WebSocket.Server({ port: 8080 });

wss.on('connection', (ws) => {
  ws.on('message', (message) => {
    // Validate untrusted input and use secure platform APIs
    const command = validateInput(message);
    if (!command) {
      return;
    }

    // Apply least privilege and explicit allowlists where relevant
    const allowedCommands = ['build', 'attack', 'move'];
    if (allowedCommands.includes(command)) {
      processCommand(ws, command);
    } else {
      console.log(`Invalid command: ${command}`);
    }
  });
});

function validateInput(message) {
  // Validate untrusted input and use secure platform APIs
  const input = message.trim();
  if (!input || !input.length) {
    return;
  }

  // Check for malicious input
  if (input.includes(';') || input.includes('`')) {
    console.log(`Invalid input: ${input}`);
    return;
  }

  // Use secure platform APIs to validate the input
  const validInput = securePlatformApi.validateInput(input);
  if (!validInput) {
    console.log(`Invalid input: ${input}`);
    return;
  }

  return validInput;
}

function processCommand(ws, command) {
  // Process the command immediately without sequence numbers or timestamps
  const data = JSON.parse(command);
  if (data.type === 'build') {
    buildUnit(ws, data.unitType, data.position);
  } else if (data.type === 'attack') {
    attackTarget(ws, data.target);
  } else if (data.type === 'move') {
    moveUnits(ws, data.units, data.destination);
  } else {
    console.log(`Invalid command: ${command}`);
  }
}

function buildUnit(ws, unitType, position) {
  // Build the unit and send it to the client
  const unit = createUnit(unitType, position);
  ws.send(JSON.stringify({ type: 'build', unit }));
}

function attackTarget(ws, target) {
  // Attack the target and send the result to the client
  const result = attack(target);
  ws.send(JSON.stringify({ type: 'attack', result }));
}

function moveUnits(ws, units, destination) {
  // Move the units to the destination and send the result to the client
  const result = move(units, destination);
  ws.send(JSON.stringify({ type: 'move', result }));
}

function createUnit(unitType, position) {
  // Create a new unit with the given type and position
  return {
    type: unitType,
    position,
  };
}

function attack(target) {
  // Attack the target and return the result
  return {
    success: true,
    damage: 10,
  };
}

function move(units, destination) {
  // Move the units to the destination and return the result
  return {
    success: true,
    units,
    destination,
  };
}